	VMOV	V25.B16, V27.B16
	// --- round group 13 ---
	VLD1.P	16(R4), [V28.S4]
	VADD	V28.S4, V1.S4, V30.S4
	SHA256H	V30.S4, V5, V4
	SHA256H2	V30.S4, V6, V5
	VMOV	V4.B16, V6.B16
	VADD	V28.S4, V8.S4, V31.S4
	SHA256H	V31.S4, V12, V11
	SHA256H2	V31.S4, V13, V12
	VMOV	V11.B16, V13.B16
	VADD	V28.S4, V15.S4, V30.S4
	SHA256H	V30.S4, V19, V18
	SHA256H2	V30.S4, V20, V19
	VMOV	V18.B16, V20.B16
	VADD	V28.S4, V22.S4, V31.S4
	SHA256H	V31.S4, V26, V25
	SHA256H2	V31.S4, V27, V26
	VMOV	V25.B16, V27.B16
	// --- round group 14 ---
	VLD1.P	16(R4), [V28.S4]
	VADD	V28.S4, V2.S4, V30.S4
	SHA256H	V30.S4, V5, V4
	SHA256H2	V30.S4, V6, V5
	VMOV	V4.B16, V6.B16
	VADD	V28.S4, V9.S4, V31.S4
	SHA256H	V31.S4, V12, V11
	SHA256H2	V31.S4, V13, V12
	VMOV	V11.B16, V13.B16
	VADD	V28.S4, V16.S4, V30.S4
	SHA256H	V30.S4, V19, V18
	SHA256H2	V30.S4, V20, V19
	VMOV	V18.B16, V20.B16
	VADD	V28.S4, V23.S4, V31.S4
	SHA256H	V31.S4, V26, V25
	SHA256H2	V31.S4, V27, V26
	VMOV	V25.B16, V27.B16
	// --- round group 15 ---
	VLD1.P	16(R4), [V28.S4]
	VADD	V28.S4, V3.S4, V30.S4
	SHA256H	V30.S4, V5, V4
	SHA256H2	V30.S4, V6, V5
	VMOV	V4.B16, V6.B16
	VADD	V28.S4, V10.S4, V31.S4
	SHA256H	V31.S4, V12, V11
	SHA256H2	V31.S4, V13, V12
	VMOV	V11.B16, V13.B16
	VADD	V28.S4, V17.S4, V30.S4
	SHA256H	V30.S4, V19, V18
	SHA256H2	V30.S4, V20, V19
	VMOV	V18.B16, V20.B16
	VADD	V28.S4, V24.S4, V31.S4
	SHA256H	V31.S4, V26, V25
	SHA256H2	V31.S4, V27, V26
	VMOV	V25.B16, V27.B16

	// Finalize: digest = REV32(state + IV); store 4*32 bytes.
	MOVD	$·sha256mbIV(SB), R4
	// lane 0: state += IV, byte-swap, store 32 bytes
	VLD1	(R4), [V29.S4]
	VADD	V29.S4, V4.S4, V4.S4
	ADD	$16, R4, R3
	VLD1	(R3), [V29.S4]
	VADD	V29.S4, V5.S4, V5.S4
	VREV32	V4.B16, V4.B16
	VREV32	V5.B16, V5.B16
	VST1.P	[V4.B16], 16(R0)
	VST1.P	[V5.B16], 16(R0)
	// lane 1: state += IV, byte-swap, store 32 bytes
	VLD1	(R4), [V29.S4]
	VADD	V29.S4, V11.S4, V11.S4
	ADD	$16, R4, R3
	VLD1	(R3), [V29.S4]
	VADD	V29.S4, V12.S4, V12.S4
	VREV32	V11.B16, V11.B16
	VREV32	V12.B16, V12.B16
	VST1.P	[V11.B16], 16(R0)
	VST1.P	[V12.B16], 16(R0)
	// lane 2: state += IV, byte-swap, store 32 bytes
	VLD1	(R4), [V29.S4]
	VADD	V29.S4, V18.S4, V18.S4
	ADD	$16, R4, R3
	VLD1	(R3), [V29.S4]
	VADD	V29.S4, V19.S4, V19.S4
	VREV32	V18.B16, V18.B16
	VREV32	V19.B16, V19.B16
	VST1.P	[V18.B16], 16(R0)
	VST1.P	[V19.B16], 16(R0)
	// lane 3: state += IV, byte-swap, store 32 bytes
	VLD1	(R4), [V29.S4]
	VADD	V29.S4, V25.S4, V25.S4
	ADD	$16, R4, R3
	VLD1	(R3), [V29.S4]
	VADD	V29.S4, V26.S4, V26.S4
	VREV32	V25.B16, V25.B16
	VREV32	V26.B16, V26.B16
	VST1.P	[V25.B16], 16(R0)
	VST1.P	[V26.B16], 16(R0)

	// Advance src to the next lane group and dst already moved via stores.
	ADD	R5, R8, R1
	SUBS	$4, R2, R2
	BNE	loop
done:
	RET

